def safe_int(campo: str, valor: str):
    texto = valor.strip()
    if texto == "":
        return (False, None, f"ERROR en '{campo}': vacío (raw={valor!r})")
    try:
        return (True, int(texto), None)
    except ValueError:
        return (False, None, f"ERROR en '{campo}': no se pudo convertir {valor!r} a int")

for v in [" 21 ", "", "abc", "  "]:
    print(repr(v), "→", safe_int("edad", v))

from decimal import Decimal, ROUND_HALF_EVEN, InvalidOperation

def parse_edad_monto(edad_txt: str, monto_txt: str) -> dict:
    raw = {"edad": edad_txt, "monto": monto_txt}
    clean = {"edad": None, "monto": None}
    errors = []
    t = edad_txt.strip()
    if t == "":
        errors.append(f"ERROR en 'edad': vacío (raw={edad_txt!r})")
    else:
        try:
            clean["edad"] = int(t)
        except ValueError:
            errors.append(f"ERROR en 'edad': no se pudo convertir {edad_txt!r} a int")
    m = monto_txt.strip()
    if m == "":
        errors.append(f"ERROR en 'monto': vacío (raw={monto_txt!r})")
    else:
        try:
            clean["monto"] = Decimal(m).quantize(Decimal("0.01"), rounding=ROUND_HALF_EVEN)
        except InvalidOperation:
            errors.append(f"ERROR en 'monto': no se pudo convertir {monto_txt!r} a Decimal")
    return {"raw": raw, "clean": clean, "errors": errors}

print("ambos OK", parse_edad_monto("34", "150.50"))
print("edad bad", parse_edad_monto("abc", "99.00"))
print("monto bad", parse_edad_monto("21", "xx"))

